INSERT INTO spots VALUES('92f490a3-4f32-45ec-9d99-e7329f3c564e','fukuyama-castle-loop','福山城外周','ふくやまじょうがいしゅう','広島県','福山市',34.48870900000000006,133.3612369999999885,'福山駅北口の目の前にある福山城公園を、南側から東西の街路と北側の公園外周で一周する約2.5kmのコースです。復元された天守や伏見櫓、月見櫓、石垣を近くに眺められ、列車の待ち時間や出張時の短い朝ランにも使いやすい立地です。駅前と公園内は歩行者が多いため、混雑時は速度を落として走ってください。','JR福山駅北口からすぐ',1,0,1,1,0,0,1,1,'partial',NULL,1,1783836312000,1783836317576);
INSERT INTO spots VALUES('21d4dd23-2e27-4865-b948-0a35daa98f8c','hikone-castle-loop','彦根城外周','ひこねじょうがいしゅう','滋賀県','彦根市',35.27067399999999964,136.2532160000000089,'彦根城のいろは松付近から、中堀・外堀の名残に沿って城郭を大きく一周する約4.9kmのコースです。国宝天守を望む場所や玄宮園周辺、夢京橋キャッスルロードを通り、平坦な城下町を走れます。彦根駅から徒歩圏で旅ランにも便利です。観光地の歩道と生活道路を通るため、混雑時は歩行者を優先してください。','JR彦根駅から西へ徒歩約15分',1,0,1,0,0,0,1,1,'partial',NULL,1,1783836312000,1783836314110);
INSERT INTO spots VALUES('164a95e9-3486-4a9e-821f-dfe53a4515cd','himeji-castle-loop','姫路城外周','ひめじじょうがいしゅう','兵庫県','姫路市',34.83485499999999747,134.6938839999999971,'姫路城の大手門前を起点に、城見台公園、兵庫県立歴史博物館、シロトピア記念公園、千姫の小径をつないで城郭を大きく一周する約5.3kmのコースです。白い大天守をさまざまな方向から望め、内堀や中堀の名残、城下町の街並みも楽しめます。公園内や観光客の多い場所では歩行者を優先して走ってください。','JR・山陽電鉄 姫路駅から大手前通りを北へ約1km',1,1,1,0,0,0,1,1,'partial',NULL,1,1783836312000,1783836312746);
INSERT INTO spots VALUES('754d3f26-2fa2-4f81-8092-e411e35af410','kochi-castle-loop','高知城外周','こうちじょうがいしゅう','高知県','高知市',33.55888800000000317,133.5299950000000138,'高知城の追手門側から、県庁前、高知城歴史博物館周辺、城西公園側をつないで城山を一周する約3.4kmの市街地コースです。現存天守と追手門を同時に望め、石垣や堀の景観を眺めながら走れます。高知市中心部のホテルから入りやすく、短い朝ランにも適します。交差点と観光客の多い追手門付近では速度を落としてください。','とさでん交通 高知城前電停から徒歩約5分',1,0,1,0,0,0,1,1,'partial',NULL,1,1783836312000,1783836498365);
INSERT INTO spots VALUES('abb716ac-282f-4b27-882d-2d09368a929d','kumamoto-castle-loop','熊本城外周','くまもとじょうがいしゅう','熊本県','熊本市中央区',32.79969499999999983,130.7044140000000141,'桜の馬場城彩苑付近から、長塀、加藤神社側、二の丸広場、県立美術館周辺をつないで熊本城を一周する約5.1kmのコースです。復旧が進む天守や宇土櫓、長い石垣を多方向から眺められ、適度な起伏もあります。園内の通行規制は復旧工事などで変わることがあるため現地案内に従い、観光客の多い場所では歩いてください。','熊本市電 花畑町電停または熊本城・市役所前電停から徒歩約10分',1,0,1,0,0,0,1,1,'partial',NULL,1,1783836312000,1783836315409);
INSERT INTO spots VALUES('4f104f4c-a9cd-4c9f-b5e1-97e32bc1a6b9','matsue-castle-loop','松江城外周','まつえじょうがいしゅう','島根県','松江市',35.4700640000000007,133.0500209999999867,'国宝松江城の南側から堀川沿いを進み、塩見縄手、城山公園北側、県庁周辺をつないで一周する約4kmのコースです。現存天守と石垣、堀、武家屋敷の街並みが続き、水の都らしい景色を楽しめます。ほぼ平坦で朝ランにも使いやすい一方、塩見縄手など狭い歩道では歩行者と車に注意してください。','一畑電車 松江しんじ湖温泉駅から徒歩約15分。JR松江駅からバスで国宝松江城県庁前下車',1,0,1,0,0,1,1,1,'partial',NULL,1,1783836312000,1783836314532);
INSERT INTO spots VALUES('3d7d4f8e-f61c-4e1a-a6ab-590183c82c63','matsumoto-castle-loop','松本城外周','まつもとじょうがいしゅう','長野県','松本市',36.23669900000000154,137.9690060000000073,'国宝松本城の南側を起点に、外堀沿いと城西・城北の街路を一周する約2.9kmのフラットなコースです。黒い天守と北アルプスを望みながら短時間で走れ、松本市街の朝ランや旅ランに向きます。城内の見学路ではなく一般の歩道を使い、交差点と観光客の多い区間では速度を落としてください。','JR松本駅から徒歩約15分。松本周遊バスの松本城・市役所前バス停からすぐ',1,0,1,0,0,0,1,1,'partial',NULL,1,1783836312000,1783836313173);
INSERT INTO spots VALUES('80718899-e01e-4c62-b594-522b06dd6f6b','okayama-castle-korakuen','岡山城・後楽園周回','おかやまじょう・こうらくえんしゅうかい','岡山県','岡山市北区',34.66519799999999662,133.9348819999999876,'岡山城南側から旭川を渡り、後楽園の外周と旭川河畔をめぐって戻る約5.4kmの周回です。黒い天守、月見橋、川越しの城郭、後楽園周辺の緑を一度に楽しめます。岡山市の遊歩道「岡山城ルート」が整備されているエリアで、中心街のホテルからも入りやすい観光ランです。橋や園路では歩行者を優先してください。','岡山電気軌道 城下電停から徒歩約10分。岡山駅から約2km',1,0,1,0,0,0,1,1,'partial',NULL,1,1783836312000,1783836313665);
INSERT INTO spots VALUES('ab8b9592-0e74-433b-a26d-29078b75a1e7','takaoka-castle-park','高岡古城公園周回','たかおかこじょうこうえんしゅうかい','富山県','高岡市',36.74604500000000228,137.0180080000000089,'高岡城跡を整備した高岡古城公園の園路と外周を一周する約3.3kmのコースです。城跡の約3分の1を占める水濠、土塁、緑の多い園内をめぐり、季節ごとの景色を楽しめます。高岡市中心部にあり駅からもアクセスしやすく、短時間のジョギングや周回追加による距離調整に向きます。園内では散策者を優先してください。','あいの風とやま鉄道 高岡駅から徒歩約15分。万葉線 急患医療センター前電停から徒歩約3分',1,1,1,0,0,0,1,1,'partial',NULL,1,1783836312000,1783836497969);
INSERT INTO spots VALUES('113eb794-34ad-48ad-966e-0acc34d8abbe','toyama-castle-park','富山城址公園周回','とやまじょうしこうえんしゅうかい','富山県','富山市',36.69029100000000198,137.2104669999999942,'富山城址公園の南側から松川沿い、市役所周辺、県庁前公園をつないで一周する約3.2kmの市街地コースです。富山城の天守、石垣、堀と松川の水辺を眺められ、富山駅周辺のホテルから朝ランでアクセスできます。桜の季節は松川沿いが混雑するため早朝を選び、横断部では信号と歩行者に注意してください。','富山地方鉄道 国際会議場前電停からすぐ。JR富山駅から約1km',1,1,1,0,0,0,1,1,'partial',NULL,1,1783836312000,1783836318005);
INSERT INTO spots VALUES('9e11485a-08fe-4302-9424-ee76c5c523f8','tsurugajo-loop','鶴ヶ城外周','つるがじょうがいしゅう','福島県','会津若松市',37.484174000000003,139.9269889999999919,'鶴ヶ城公園の南側から、三ノ丸、北出丸、西出丸周辺の街路をつないで城郭を一周する約4.1kmのコースです。赤瓦の天守、石垣、堀を眺めながら会津の歴史を感じられ、城下町観光と組み合わせやすい距離です。桜や紅葉の時期は混雑するため早朝が走りやすく、積雪期は路面状況を確認してください。','まちなか周遊バス 鶴ヶ城入口または鶴ヶ城三ノ丸口バス停からすぐ',1,0,1,0,0,0,1,1,'partial',NULL,1,1783836312000,1783836316720);
